import React, { Fragment } from 'react';
import {Card, CardContent, CardHeader, Typography, Grid, Link, CardActions, Button, CardActionArea, CardMedia} from '@material-ui/core';
import {makeStyles} from '@material-ui/core/styles';
import {projects} from '../helper';

export default function ProjectsGrid(){
  const classes = makeStyles({
    root: {
      flexGrow: 1
    }
  })();
  const projectItems = projects.map((project, index) => {
    return(ProjectItem(project, index));
  });
  return(
    <div className={classes.root}>
      <Grid container spacing={2} alignItems="flex-end">
          {projectItems}
      </Grid>
    </div>
  );
}
const ProjectItem = (project, index) => {
  const classes = makeStyles({
    media: {
      height: 0,
      paddingTop: '56.25%', // 16:9,
    },
  })();
  // const classes = useStyles();
  return(
    <Grid item xs={12} sm={6} lg={4} key={index} className="stretched-card">
      <Card variant="outlined" >
        <CardActionArea>
          <CardMedia
            className={classes.media}
            image={project.media}
            title={project.name}
            />
        </CardActionArea>
        <CardHeader title={project.name}/>
        <CardContent className={classes.card}>
          {Description(project.description)}
          
        </CardContent>
        <CardActions>
          <GithubButton href={project.githubUrl} />
          <LivePreviewButton href="/" />
        </CardActions>
      </Card>
    </Grid>
  );
}

function GithubButton(props){
  return(
    <Link underline="none" target="_blank" href={props.href}>
      <Button variant="outlined" color="secondary">Github</Button>
    </Link>
  );
}
function LivePreviewButton(props){
  return(
    <Link underline="none" target="_blank" href={props.href}>
      <Button variant="outlined" color="primary">Live Preview</Button>
    </Link>
  );
}
function Description(text){
  const splittedText = text.split('**');
  const finalDescription = splittedText.map((str, index) => {
    if(index % 2 === 0) {
      return(
        <Typography variant="body1" color="textSecondary" component="span" key={index}>
          {str}
        </Typography>
        );
      }else{
        return(
          <Typography variant="body1" color="textPrimary" component="span" key={index}>
            {str}
          </Typography>
        );
      }
  });
  return (
    <Fragment>

      {finalDescription}
    </Fragment>
  );
};
