import React from 'react';
import { Box, Grid, Container, Typography} from '@material-ui/core';
import {skills} from '../helper';
export default function MySkills(){
  const skillsList = skills.map((skill, index) => {
    return(
      <Box component="span" alignItems="center" style={{paddingLeft:20}}>
        <img key={index} src={skill.src} alt={skill.alt} className="skill-img" style={{
          height: 30,
        }}/>
        </Box>
    );
  });
  return (
    <Box m={3}>
      <Grid>
        <Grid item xs={3}>
          <Typography variant="h4" component="span" style={{alignSelf: 'center', flexDirection: 'column'}}>
            My Skills:
          </Typography>
        </Grid>
        <Grid item xs={9}>
        <Box alignItems="center" component="span">
          {skillsList}
          </Box>
        </Grid>
      </Grid>
    </Box>
  );
}